ang="EN-US" class="TextRun SCXW31228399 BCX2"&gt;&lt;span class="NormalTextRun CommentHighlightClicked SCXW31228399 BCX2"&gt; &lt;/span&gt;&lt;/span&gt;&lt;a class="Hyperlink SCXW31228399 BCX2" style="text-decoration: none; color: inherit;" target="_blank" rel="noreferrer noopener"&gt;&lt;span style="color: rgb(70, 120, 134); font-size: 10.5pt; text-decoration: underline; line-height: 18px; font-family: &amp;quot;Amazon Ember&amp;quot;, &amp;quot;Amazon Ember_EmbeddedFont&amp;quot;, sans-serif;" data-contrast="none" lang="EN-US" class="TextRun Underlined SCXW31228399 BCX2"&gt;&lt;span class="NormalTextRun CommentHighlightClicked SCXW31228399 BCX2" data-ccp-charstyle="Hyperlink"&gt;AWS Cost Management documentation.&lt;/span&gt;&lt;/span&gt;&lt;/a&gt;&lt;span data-contrast="auto" style="font-size: 10.5pt; line-height: 18px; font-family: &amp;quot;Amazon Ember&amp;quot;, &amp;quot;Amazon Ember_EmbeddedFont&amp;quot;, sans-serif;" lang="EN-US" class="TextRun SCXW31228399 BCX2"&gt;&lt;span class="NormalTextRun CommentHighlightClicked SCXW31228399 BCX2"&gt; &lt;/span&gt;&lt;/span&gt;&lt;span class="EOP CommentHighlightClicked SCXW31228399 BCX2" style="font-size: 10.5pt; line-height: 18px; font-family: &amp;quot;Amazon Ember&amp;quot;, &amp;quot;Amazon Ember_EmbeddedFont&amp;quot;, sans-serif;" data-ccp-props="{&amp;quot;335551550&amp;quot;:0,&amp;quot;335551620&amp;quot;:0}"&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt; 
